import { Component, OnInit, OnDestroy, ViewChild, ElementRef, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ChatService, ChatConversation, ChatMessage } from '../../services/chat.service';
import { AuthService } from '../../services/Base/auth.service';
import { BehaviorSubject, combineLatest, map, Observable } from 'rxjs';
import { LucideAngularModule } from 'lucide-angular';

type ConversationItem = 
  | { type: 'conversation'; data: ChatConversation }
  | { type: 'contact'; data: StaffContact };

interface StaffContact {
  id: string;
  first_name: string;
  last_name: string;
  avatar_url: string | null;
}

@Component({
  selector: 'app-chat-window',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './chat-window.html',
  styleUrls: ['./chat-window.css']
})
export class ChatWindow implements OnInit, OnDestroy {
  private chatService = inject(ChatService);
  private authService = inject(AuthService);
  private staffContactsSubject = new BehaviorSubject<StaffContact[]>([]);
  private isCreating = false;
  private visualViewportListener = () => this.adjustForKeyboard();
  private isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);

  staffContacts$ = this.staffContactsSubject.asObservable();

  // Observables pubblici
  conversations$ = this.chatService.conversations$;
  activeConversation$ = this.chatService.activeConversation$;
  messages$ = this.chatService.messages$;
  loading$ = this.chatService.loading$;
  
  conversationsWithUnread$ = combineLatest([
    this.conversations$,
    this.chatService.unreadCount$
  ]).pipe(
    map(([conversations, unreadMap]) => 
      conversations.map(conv => ({
        ...conv,
        unread: unreadMap.get(conv.id) || 0
      }))
    )
  );

  // Utente corrente
  currentUserId = this.authService.currentUserValue?.id;

  // Nuovo messaggio
  newMessage = '';

  // Riferimento al contenitore dei messaggi per scroll
  @ViewChild('scrollContainer') private scrollContainer!: ElementRef;

  // Per modale nuova chat (opzionale, se vuoi implementarla subito)
  showNewChatModal = false;
  staffList: any[] = []; // popoleremo se necessario

  ngOnInit() {
    this.chatService.loadConversations();
    this.loadStaffContacts();

    // Ricarica i contatti quando cambia ristorante
    this.authService.activeRestaurantId$.subscribe(() => {
      this.loadStaffContacts();
    });

    this.messages$.subscribe(() => {
      setTimeout(() => this.scrollToBottom(), 100);
    });
    // Aggiungi listener per la tastiera su mobile
    if (this.isMobile && window.visualViewport) {
      window.visualViewport.addEventListener('resize', this.visualViewportListener);
      // Imposta altezza iniziale dopo un breve ritardo
      setTimeout(() => this.adjustForKeyboard(), 100);
    }
  }

private async loadStaffContacts() {
  const restaurantId = this.authService.getCurrentRestaurantId();
  const currentUserId = this.authService.currentUserValue?.id;
  console.log('🔍 loadStaffContacts - chiamato con:', { restaurantId, currentUserId });

  if (!restaurantId || !currentUserId) return;

  // Recupera il proprietario
  const { data: restaurant } = await this.chatService['supabase'].getSupabaseClient()
    .from('restaurants')
    .select('owner_id')
    .eq('id', restaurantId)
    .single();

  const ownerId = restaurant?.owner_id;

  // Recupera lo staff accettato (escluso l'utente corrente)
  // Usiamo un join esplicito con la tabella users
  const { data: staffData, error } = await this.chatService['supabase'].getSupabaseClient()
    .from('restaurant_staff')
    .select(`
      user_id,
      users:user_id (
        id,
        first_name,
        last_name,
        avatar_url
      )
    `)
    .eq('restaurant_id', restaurantId)
    .eq('invitation_status', 'accepted')
    .neq('user_id', currentUserId);

  if (error) {
    console.error('❌ Errore nel recuperare lo staff:', error);
  }

  const staffContacts = (staffData || [])
    .map((item: any) => item.users)
    .filter(user => user && user.id); // filtro per sicurezza

  // Aggiungi il proprietario se non è già presente
  if (ownerId && ownerId !== currentUserId) {
    const alreadyIncluded = staffContacts.some(c => c.id === ownerId);
    if (!alreadyIncluded) {
      const { data: ownerUser } = await this.chatService['supabase'].getSupabaseClient()
        .from('users')
        .select('id, first_name, last_name, avatar_url')
        .eq('id', ownerId)
        .single();

      if (ownerUser) {
        staffContacts.push(ownerUser);
      }
    }
  }

  console.log('✅ Contatti finali:', staffContacts);
  this.staffContactsSubject.next(staffContacts);
}

async onSelectItem(item: ConversationItem) {
  if (this.isCreating) return;

  if (item.type === 'conversation') {
    this.chatService.setActiveConversation(item.data);
  } else {
    this.isCreating = true;
    try {
      console.log('🔵 Chiamata createDirectConversation per:', item.data.id);
      const conv = await this.chatService.createDirectConversation(item.data.id);
      console.log('🔵 Risultato createDirectConversation:', conv);
      if (conv) {
        this.chatService.setActiveConversation(conv);
      }
    } finally {
      this.isCreating = false;
    }
  }
}



  ngOnDestroy() {
    // Pulisci conversazione attiva
    this.chatService.setActiveConversation(null);
    if (this.isMobile && window.visualViewport) {
      window.visualViewport.removeEventListener('resize', this.visualViewportListener);
    }
  }

  // Seleziona una conversazione
  selectConversation(conv: ChatConversation) {
    this.chatService.setActiveConversation(conv);
  }

  // Invia messaggio
sendMessage() {
  const active = this.chatService.activeConversationSubject.value;
  if (!active || !this.newMessage.trim()) return;

  this.chatService.sendMessage(active.id, this.newMessage);
  this.newMessage = '';
}

  private doSendMessage() {
    const active = this.chatService.activeConversationSubject.value;
    if (!active || !this.newMessage.trim()) return;

    this.chatService.sendMessage(active.id, this.newMessage);
    this.newMessage = '';
  }

  // Modifica messaggio
  editMessage(msg: ChatMessage) {
    const newContent = prompt('Modifica messaggio', msg.content);
    if (newContent && newContent !== msg.content) {
      this.chatService.updateMessage(msg.id, newContent);
    }
  }

  // Cancella messaggio
  deleteMessage(messageId: string) {
    if (confirm('Eliminare questo messaggio?')) {
      this.chatService.deleteMessage(messageId);
    }
  }

  // Verifica se può modificare/cancellare (entro 4 ore)
  canEditOrDelete(msg: ChatMessage): boolean {
    const fourHoursAgo = new Date(Date.now() - 4 * 60 * 60 * 1000);
    return new Date(msg.created_at) > fourHoursAgo;
  }

  // Scroll in basso
  private scrollToBottom(): void {
    try {
      this.scrollContainer.nativeElement.scrollTop = this.scrollContainer.nativeElement.scrollHeight;
    } catch (err) {}
  }

  // Metodi per la modale nuova chat (opzionali)
  openNewChatModal() {
    // Qui carichi la lista dello staff del ristorante corrente
    // Esempio: this.loadStaffList();
    this.showNewChatModal = true;
  }

  closeNewChatModal() {
    this.showNewChatModal = false;
  }

  startDirectChat(userId: string) {
    this.chatService.createDirectConversation(userId).then(() => {
      this.closeNewChatModal();
    });
  }

onKeydown(event: Event) {
  const keyboardEvent = event as KeyboardEvent;
  if (keyboardEvent.key === 'Enter' && !keyboardEvent.shiftKey) {
    keyboardEvent.preventDefault();
    this.sendMessage();
  }
}

  // Observable unificato per la sidebar
conversationItems$: Observable<ConversationItem[]> = this.conversations$.pipe(
  map(conversations => conversations.map(conv => ({ type: 'conversation', data: conv })))
);

// ADATTA ALTEZZA TASTIERA MOBILE
  private adjustForKeyboard() {
    const vv = window.visualViewport;
    if (!vv) return;

    const chatMain = document.querySelector('.chat-main') as HTMLElement;
    const messagesContainer = document.querySelector('.messages-container') as HTMLElement;
    if (chatMain && messagesContainer) {
      const header = chatMain.querySelector('.chat-header') as HTMLElement;
      const input = chatMain.querySelector('.message-input') as HTMLElement;
      
      const headerHeight = header?.offsetHeight || 0;
      const inputHeight = input?.offsetHeight || 0;

      // Imposta altezza del container messaggi
      messagesContainer.style.height = `${vv.height - headerHeight - inputHeight}px`;
      
      // Scroll in basso dopo il resize
      setTimeout(() => this.scrollToBottom(), 50);
    }
  }

}